// Time:  O(n)
// Space: O(1)

// freq table
class Solution {
public:
    string findValidPair(string s) {
        vector<int> cnt(9);
        for (const auto& x : s) {
            ++cnt[x - '1'];
        }
        for (int i = 0; i + 1 < size(s); ++i) {
            if (s[i] != s[i + 1] && cnt[s[i] - '1'] == s[i] - '0' && cnt[s[i + 1] - '1'] == s[i + 1] - '0') {
                return s.substr(i, 2);
            }
        }
        return "";
    }
};

# Time:  O(n)
# Space: O(1)

# freq table
class Solution(object):
    def findValidPair(self, s):
        """
        :type s: str
        :rtype: str
        """
        cnt = [0]*9
        for x in s:
            cnt[ord(x)-ord('1')] += 1
        for i in xrange(len(s)-1):
            if s[i] != s[i+1] and cnt[ord(s[i])-ord('1')] == ord(s[i])-ord('0') and cnt[ord(s[i+1])-ord('1')] == ord(s[i+1])-ord('0'):
                return s[i:i+2]
        return ""
